	('824fd83d-16c3-4a07-8757-d4e48e4135c8', '{"skills": ["PHP", "JavaScript", "TypeScript", "ECMAScript 6 (ES6)", "Python", "HTML", "CSS", "Sass", "Symfony", "Laravel", "React.js", "Vue.js", "Angular", "Node.js", "Express.js", "Flask", "jQuery", "API Platform", "MySQL", "MongoDB", "MariaDB", "Git", "Continuous Integration / Continuous Delivery (CI/CD)", "User Interface / User Experience Design (UI/UX)", "Docker", "Microsoft Azure", "Amazon Web Services (AWS)", "Material Design", "Bootstrap", "GitLab", "Twig", "OpenSSL", "REST API", "Pandas", "GeoPandas", "Cron", "Cloudinary", "Slack", "Microsoft Teams", "Agile methodology", "Scrum", "Kanban", "Keyhole Markup Language (KML)", "LAMP stack", "MEAN stack", "Redux Saga", "NoSQL", "GitHub", "DICOM"], "summary": "Développeur Fullstack expérimenté avec 6 ans d''expertise dans la conception et le développement de solutions web robustes. Maîtrise approfondie des écosystèmes PHP (Symfony, Laravel) et JavaScript (React.js, Angular, Vue.js), complétée par des compétences en Node.js et Python. Capable de gérer le cycle de vie complet des projets, de la conception à la maintenance, en passant par le déploiement sur des infrastructures cloud.", "education": [{"year": "2020", "degree": "Développeur web et web mobile (Bac+2)", "school": "Centre Formation Konexio – PARIS 13"}, {"year": "2017", "degree": "Institut Technique Supérieur d''Informatique", "school": "Institut Camillo Olivetti – Turin - Italie"}], "strengths": ["Expertise Fullstack robuste et polyvalente, couvrant les écosystèmes PHP (Symfony, Laravel) et JavaScript (React.js, Angular, Vue.js), ainsi que Node.js et Python/Flask, démontrant une grande adaptabilité technologique.", "Maîtrise approfondie des pratiques DevOps (Docker, CI/CD, GitLab, GitHub) et des services Cloud (AWS, Azure), garantissant des déploiements efficaces et la gestion d''infrastructures résilientes.", "Expérience avérée dans le développement et l''intégration d''API (API Platform, REST API), la gestion de bases de données relationnelles (MySQL, MariaDB) et NoSQL (MongoDB), essentielle pour des architectures modernes.", "Capacité démontrée à travailler efficacement en méthodologies agiles (Scrum, Kanban), avec une forte orientation vers la résolution de bugs, la maintenance évolutive et le développement de nouvelles fonctionnalités complexes.", "Développement de solutions innovantes et variées, incluant des applications d''affichage dynamique, des outils de gestion de clients, des services de conversion de fichiers, et des systèmes d''automatisation et d''optimisation."], "experiences": [{"role": "Développeur Fullstack JavaScript PHP", "company": "CROWN HEIGHTS", "isCurrent": true, "startDate": "03/2023", "description": ["Développement de nouvelles fonctionnalités pour une solution d''affichage dynamique (Crown TV).", "Maintenance corrective et optimisation des systèmes existants.", "Développement d’une application de tests configurable pour Crown TV.", "Création et intégration d''un explorateur de dossiers de fichiers multimédias.", "Intégration d''API immobilières pour la distribution d''annonces avec Cron.", "Migration des systèmes d''alerte de Slack vers Microsoft Teams et implémentation de notifications automatiques.", "Développement d''algorithmes d''optimisation d''images avec Cloudinary."]}, {"role": "Développeur Fullstack JavaScript PHP", "company": "DEEP BLOCK", "endDate": "02/2023", "isCurrent": false, "startDate": "06/2022", "description": ["Optimisation, correction de bogues et développement de fonctionnalités pour l''application de signature virtuelle VitalSign (Symfony 5).", "Développement d''APIs et intégration de modèles/composants pour divers projets.", "Création d''une application de repos pour interagir avec des APIs tierces dans le cadre du projet OpenApi.", "Développement d''un service de conversion de fichiers (.doc, .docx, .odt, .png, .jpg, .jpeg) en PDF.", "Développement d’API certifiant l''horodatage pour des fichiers sensibles.", "Création de scripts pour automatiser des processus métier.", "Vérification et optimisation de fichiers Keyhole Markup Language (KML) pour la gestion polygonale géospatiale.", "Développement d''API pour la création de liens courts avec expiration (SHORT LINKS API)."]}, {"role": "Développeur Fullstack JavaScript", "company": "AZMED", "endDate": "05/2022", "isCurrent": false, "startDate": "10/2020", "description": ["Résolution des bugs et amélioration de l''interface utilisateur.", "Optimisation du responsive design.", "Ajout de nouveaux utilitaires et options.", "Déploiement, mise à jour et maintenance des applications.", "Développement de nouveaux utilitaires pour le produit Rayvolve IA.", "Développement et amélioration de projets internes (ToolAnalytics, site web Azmed, DICOM Azmed Viewer)."]}, {"role": "Développeur Fullstack PHP JavaScript", "company": "FREELANCER.COM", "endDate": "2020", "isCurrent": false, "startDate": "2019", "description": ["Développement de landing pages, de dashboards et de blogs.", "Développement de fonctions et méthodes pour résoudre des problèmes techniques.", "Conception et développement d''une plateforme de gestion des stagiaires pour un centre de formation laser, incluant des modules de suivi des progrès, de gestion documentaire, de gestion des présences/absences et de suivi des stages."]}, {"role": "Développeur Fullstack PHP JavaScript", "company": "FR4M3STUDIO", "endDate": "2019", "isCurrent": false, "startDate": "2017", "description": ["Développement d''un outil de gestion des clients (Médiashopping) initialement en Symfony 3, puis migration vers Symfony 4.", "Conception et développement de solutions web (vitrines internet, pages publicitaires) pour des artisans, boutiques et centres de beauté.", "Développement, mise à jour et optimisation du code source d''applications web.", "Mise en place de systèmes de gestion des données utilisateur.", "Implémentation de systèmes de notification automatisés (email, SMS).", "Optimisation de la protection des données sensibles."]}], "personalInfo": {"title": "Développeur Fullstack", "lastName": "S.", "firstName": "AAA."}}', 'https://xiphltvpnsconvlrytjc.supabase.co/storage/v1/object/public/cv-original/1773437135938_AS_-_Developpeur_Fullstack_REACT_PHP_Symfony_062023.docx', NULL, 'ready', '2026-03-13 21:25:36.690264+00', '2026-03-13 21:25:36.690264+00', NULL, 25000, 300),
	('a44687fc-a72b-406b-bc65-92c35b8e581f', '{"skills": ["JavaScript", "TypeScript", "Java", "HTML5", "CSS3", "C (programming language)", "C++", "Angular", "Node.js", "Express.js", "Redux", "Electron", "jQuery", "Functional Programming", "Reactive Programming", "Object-Oriented Programming (OOP)", "MVC (Model-View-Controller)", "Git", "Jenkins", "npm", "Webpack", "Visual Studio Code", "Firebase", "JUnit", "Karma", "Jasmine", "Spectron", "Gherkin", "Cucumber", "IntelliJ IDEA", "Scrum", "Test Driven Development", "Fastify", "GraphQL", "PostgreSQL", "RabbitMQ", "Apache Kafka", "Vitest", "GitLab CI/CD", "Docker", "Kubernetes", "Jira", "Jovo", "Netlify", "Apache Spark", "Scala", "ScalaTest", "Apache Cassandra", "Spring Boot", "Mockito", "EasyMock", "WireMock", "Spring Batch", "Apache Camel", "Apache Maven", "MySQL", "Confluence", "Clean Architecture", "Hexagonal Architecture", "Domain Driven Design", "Microservices", "Storybook", "Trello", "AWS Lambda", "Amazon DynamoDB", "Amazon S3", "Amazon CloudWatch", "Amazon API Gateway", "AWS Identity and Access Management (IAM)", "Jest", "Serverless Framework", "WebStorm", "PHP", "Content Management System", "AJAX", "XML", "JSON", "SOAP", "Web Services", "Agile", "Kanban", "Red Hat OpenShift"], "summary": "Développeur Senior Back-end expérimenté avec plus de 8 ans d''expérience dans la conception, le développement et l''optimisation de solutions logicielles robustes. Expert des écosystèmes Node.js et Java/Spring Boot, il maîtrise une large gamme de technologies back-end, bases de données et outils DevOps. Reconnu pour sa capacité à travailler sur des architectures complexes et son engagement envers les méthodologies Agile et les pratiques de développement de haute qualité.", "education": [{"year": "2016-2017", "degree": "Architecte en Technologie Numérique", "school": "École 42 (Paris)"}, {"year": "2015-2016", "degree": "Licence Informatique", "school": "Faculté des Sciences (Aix-Montperrin)"}, {"year": "2013-2015", "degree": "DUT Informatique option Imagerie Numérique", "school": "I.U.T. Arles"}, {"year": "2013", "degree": "Baccalauréat S SVT, spécialité physique", "school": "Lycée G.A. De Gaulle - Milhaud"}], "strengths": ["Expertise avérée en développement Back-end avec une forte maîtrise des écosystèmes Node.js et Java/Spring Boot.", "Compétences solides en architecture logicielle (Clean Architecture, Hexagonal Architecture, Domain Driven Design) et en méthodologies Agile (Scrum, Kanban, Test Driven Development).", "Expérience significative dans la mise en œuvre et l''optimisation de chaînes CI/CD (GitLab CI/CD, Jenkins, Docker, Kubernetes).", "Maîtrise des technologies cloud (AWS, Serverless Framework) et des bases de données SQL/NoSQL (PostgreSQL, Apache Cassandra, MySQL).", "Capacité à contribuer à l''ensemble du cycle de vie du développement, de la conception à l''optimisation des performances et au monitoring."], "experiences": [{"role": "Développeur back-end", "company": "Radio France", "endDate": "Décembre 2024", "location": "France", "isCurrent": false, "startDate": "Janvier 2023", "description": ["Développement de nouvelles fonctionnalités dans les BFF (Backend for frontend) des applications mobiles France Bleu et Radio France en utilisant la Clean Architecture.", "Refonte de l''app de Radio France vers un nouveau type de BFF plus poussé, qui en plus de renvoyer les données nécessaire, renvoie aussi l''information sur comment l''app doit afficher le contenu visuellement.", "Développement de nouvelles query dans l''api graphql afin de mettre à disposition toutes les données backend aux différentes équipes frontend pour leur BFF.", "Développement de nouvelles fonctionnalités dans les projets \"data\", c''est-à-dire les projets qui ont accès à une base de donnée, avec l''utilisation de rabbit afin de pouvoir accéder en écriture à la base de donnée.", "Développement dans le service relatif aux données de l''utilisateur, afin de transmettre à l''équipe data, les actions réalisé par l''utilisateur via kafka.", "Optimisation du temps de réponse des requêtes sql en les repensant et/ou en créant un nouvel index qui correspond à son utilisation.", "Diverses contributions à toutes les autres api/projets géré par l''équipe (~30 projets) et à toutes les librairies npm interne (~20 librairies) afin de corriger des bugs, faire des évolutions, faire des montées de versions, etc.", "Déploiement des différents services via gitlab ci et kubernetes, afin de faire du déploiement continue en réalisant plusieurs MEP par jour.", "Monitoring au quotidien via un board elastic afin d''avoir une vision globale de tous les services.", "Monitoring plus poussé via prometheus afin d''avoir des données plus précises pour chaque service, c''est en autres utilisé après chaque MEP pour s''assurer que tout se passe bien : le temps de réponse, le CPU, le nombre de réplicas, etc.", "Méthodologie Agile : Scrum."], "companyDomain": ""}, {"role": "Développeur back-end", "company": "Radio France", "endDate": "Janvier 2023", "location": "France", "isCurrent": false, "startDate": "Octobre 2021", "description": ["Développement de nouvelles expériences Radio France sur les assistants vocaux, via la création d''applications vocales, appelées \"Skill \"pour Alexa et \"Conversational Action\" pour Google Assistant.", "Développement de nouvelles fonctionnalités pour les applications vocales, via le framework Jovo (Node.js/TypeScript) qui permet de mutualiser le développement entre Alexa et Google Assistant.", "Développement d''un backend en Node.js utilisé par les applications vocales.", "Création d''un backoffice avec Netlify CMS qui permet de mettre à jour les actualités disponible sur Alexa.", "Refonte de l''architecture des applications vocales vers la Clean Architecture.", "Migration des applications vocales vers la dernière version majeur du framework en Jovo 4.", "Création d''une librairie afin de mutualiser et uniformiser le code entre nos différentes applications vocales et ainsi améliorer la maintenance et l''évolution de celles-ci.", "Création d''un template Gitlab CI/CD pour mutualiser les pipelines de déploiement des applications vocales.", "Méthodologie Agile : Scrum."], "companyDomain": ""}, {"role": "Ingénieur Études et Développement", "company": "DATANUMIA", "endDate": "Octobre 2021", "location": "", "isCurrent": false, "startDate": "Août 2019", "description": ["Développement d''un batch Spark SQL (Scala) générique pour donner la possibilité à un utilisateur de comparer sa consommation à celles d''autres utilisateurs \"similaires\".", "Optimisation du batch, afin de réduire le temps d''exécution de 4h à 25 minutes.", "Développement d''un batch Spark SQL (Scala) générique afin de réaliser une migration de données d''une table cassandra X vers une autre table cassandra Y.", "Développement d''un Batch Spark SQL (Scala), avec implémentation d''un algo en Test Driven Development.", "Développement d''un Batch Spark SQL (Scala), afin de stocker les consommations des utilisateurs.", "Développement des API en Spring Boot (Java), avec tests unitaires et tests d''intégration.", "Développement d''une nouvelle fonctionnalité front : \"quiz co2\" de manière générique.", "Evolution des fonctionnalités déjà présentes sur le portail équilibre (graph conso, foyers similaires, simulateur de chauffage etc...), avec Angular 6.", "Aider l''équipe à monter en compétence sur Angular.", "Programmation fonctionnelle avec Typescript côté Angular et Scala côté batch Spark SQL.", "Usine de build Jenkins afin de déployer sur OpenShift.", "Méthodologie Agile : Scrum.", "Développement d''un backend Spring Boot (Java 11) en architecture hexagonale.", "Implémentation de l''algo passage à un véhicule électrique en Test Driven Development.", "Développement d''un formulaire généré dynamiquement à partir d''un fichier de configuration avec Angular 9 et son api Component Factory.", "Tests de non régression e2e automatisés avec Cypress.", "Tests unitaires côté front avec jasmine.", "Usine de build Jenkins afin de déployer sur OpenShift.", "Méthodologie Agile: Kanban."], "companyDomain": ""}, {"role": "Ingénieur Études et Développement", "company": "STELLIANT", "endDate": "Juin 2019", "location": "", "isCurrent": false, "startDate": "Septembre 2017", "description": ["Framework Electron avec Node.js pour le backend.", "Presentational/Dumb component pattern avec Angular 7 pour le frontend.", "Gestion de l''état de l''application via Redux, avec une communication IPC des actions Redux afin de maintenir un state similaire entre le front et le back.", "Programmation réactive avec RxJS.", "Programmation Fonctionnelle.", "Test Driven Development/Tests End2End avec Cucumber.", "Mock server en Node.js avec Express.js.", "Backend JAVA, Clean."], "companyDomain": ""}, {"role": "Stage de programmation Web", "company": "OZON INTERACTIVE", "endDate": "Juin 2015", "location": "Nîmes", "isCurrent": false, "startDate": "Avril 2015", "description": ["Création de sites vitrines."], "companyDomain": ""}, {"role": "Stage de sélection (Piscine)", "company": "École 42 - Paris", "endDate": "", "location": "Paris", "isCurrent": false, "startDate": "Août 2014", "description": ["Programmation intensive en C pendant 1 mois.", "Admis pour la rentrée novembre 2016."], "companyDomain": ""}], "personalInfo": {"email": "", "phone": "", "title": "Développeur Senior Back end", "lastName": "V.", "location": "", "firstName": "F."}}', 'https://xiphltvpnsconvlrytjc.supabase.co/storage/v1/object/public/cv-original/1773701950757_NeoLynk_Florian_CV_2.pdf', NULL, 'ready', '2026-03-16 22:59:11.661112+00', '2026-03-16 22:59:11.661112+00', NULL, 25000, 151),
	('734b0caf-421c-4620-8f97-1f4642c184f7', '{"skills": ["Java", "Java EE", "Java Servlet", "JavaServer Pages (JSP)", "JDBC (Java Database Connectivity)", "Java Persistence API (JPA)", "Spring Framework", "Spring Boot", "Spring MVC", "Modèle-Vue-Contrôleur (MVC)", "Design Patterns", "Principes SOLID", "Programmation réseau", "Java Socket", "Intégration continue (CI)", "Déploiement continu (CD)", "VBA (Visual Basic for Applications)", "Microsoft Excel", "C (Langage)", "C++", "Python", "VB.NET", "Oracle Database", "Microsoft Access", "SQL", "PL/SQL", "SQLite", "MySQL", "HTML", "CSS", "JavaScript", "PHP", "Bootstrap", "Microsoft Word", "Microsoft PowerPoint", "GitHub", "GitLab", "PuTTY", "DevOps", "Figma", "Trello", "Modelio", "Sage (Logiciel)", "IntelliJ IDEA", "Eclipse IDE", "Algorithmique", "Tests unitaires", "JUnit", "Test Driven Development (TDD)", "Android Studio", "XML", "Retrofit (Android)", "PostgreSQL", "Railway (Plateforme)", "API REST", "API"], "summary": "Actuellement étudiant en 3ème année de BUT Informatique, Nicolas CHANJOU est à la recherche d''un stage pour approfondir ses compétences en développement logiciel. Motivé et curieux, il souhaite contribuer activement aux projets d''une équipe dynamique. Il possède déjà une solide base technique en Java, Spring et le développement mobile Android, acquise au travers de divers projets académiques et personnels.", "education": [{"year": "2023-2026", "degree": "BUT Informatique", "school": "IUT Paris Rives de Seine"}, {"year": "2023", "degree": "BTS de Comptabilité et Gestion", "school": "Lycée de Courbevoie"}, {"year": "2021", "degree": "BAC STMG Mention Bien, Spécialités Gestion Finance", "school": "Lycée de Courbevoie"}], "strengths": ["Compétences solides en Java et Spring, avec une expérience pratique en développement back-end et mobile (Android).", "Maîtrise des concepts fondamentaux du développement logiciel, y compris la POO, les Design Patterns, les Principes SOLID et les Tests unitaires (JUnit, TDD).", "Expérience des outils et méthodologies de développement modernes comme GitHub, GitLab, CI/CD et gestion de projet (Trello).", "Polyvalence technique démontrée par la connaissance de multiples langages (Java, C, C++, Python, VBA) et bases de données (SQL, MySQL, PostgreSQL).", "Autonome et rigoureux dans la conception et le développement de projets, avec une capacité d''adaptation et un esprit d''équipe."], "experiences": [{"role": "Stagiaire en Informatique", "company": "CSF", "isCurrent": true, "startDate": "2025", "description": ["Installation et mise à jour d''une application de planification de projets sur un nouveau serveur", "Utilisation de Java, Web Service, GitLab, PuTTY"]}, {"role": "Stagiaire Assistant Comptable", "company": "Jerard Créatis", "isCurrent": false, "startDate": "2022", "description": ["Passage des écritures pour de multiples entreprises de différents statuts"]}, {"role": "Développeur Java / POO (Projet Académique)", "company": "IUT Paris Rives de Seine", "endDate": "2026", "isCurrent": false, "startDate": "2023", "description": ["Implémentation de l''algorithme de Dijkstra", "Utilisation des piles et listes chaînées", "Utilisation de l''héritage et du polymorphisme", "Mise en place de Tests unitaires JUnit"]}, {"role": "Développeur VBA (Projet Personnel)", "company": "Projet Personnel", "endDate": "2024", "isCurrent": false, "startDate": "2023", "description": ["Développement d''un outil Microsoft Excel de gestion de stock avec suivi des ventes et du chiffre d''affaires.", "Automatisation de l''import de données (TXT/CSV) et création de macros VBA (fiches produits, suivi des stocks, calcul des bénéfices).", "Conception d''un tableau de bord avec indicateurs clés (best-sellers, volumes de ventes, bénéfice mensuel).", "Projet réalisé en autonomie : conception, développement et tests."]}, {"role": "Développeur Mobile Android (Projet Personnel)", "company": "Projet Personnel", "endDate": "2025", "isCurrent": false, "startDate": "2024", "description": ["Développement d''une application mobile Android de suivi de l''usage et de la consommation énergétique (jeux, applications, temps d''écran).", "Conception d''un backend API REST sécurisé avec Spring Boot (authentification, gestion des utilisateurs, base de données, déploiement cloud).", "Intégration d''API externes (Steam) pour enrichir les données et affiner l''analyse des usages."]}], "personalInfo": {"email": "nicolas.chanjou@gmail.com", "phone": "06 95 66 23 66", "title": "Développeur Junior - Étudiant en BUT Informatique", "lastName": "CHANJOU", "location": "Courbevoie 92400", "firstName": "Nicolas"}}', 'https://xiphltvpnsconvlrytjc.supabase.co/storage/v1/object/public/cv-original/1773654035429_CHANJOU_Nicolas_CV.pdf', NULL, 'reviewing', '2026-03-16 09:40:36.270874+00', '2026-03-16 09:40:36.270874+00', NULL, 25000, 0),
	('d06e01ba-c576-46cc-a769-a4c58fa43b11', '{"skills": ["Java", "JEE", "Servlets", "JSP", "JDBC", "JPA", "Spring Framework", "Spring MVC", "Spring Boot", "Modèle-vue-contrôleur (MVC)", "Design Patterns", "SOLID (Principes de la programmation orientée objet)", "Java (Programmation réseau)", "Intégration et Déploiement Continus (CI/CD)", "VBA (Visual Basic for Applications)", "C (Langage de programmation)", "C++ (Langage de programmation)", "Python", "VB.NET", "Oracle Database", "Microsoft Access", "SQL", "PL/SQL", "SQLite", "MySQL", "HTML", "CSS", "JavaScript", "PHP", "Bootstrap", "Microsoft Word", "Microsoft Excel", "Microsoft PowerPoint", "GitHub", "GitLab", "PuTTY", "DevOps", "Figma", "Trello", "Modélisation (UML/Merise)", "Sage (Logiciel de gestion)", "IntelliJ IDEA", "Eclipse (IDE)", "Algorithme de Dijkstra", "Structures de données (Piles)", "Structures de données (Listes chaînées)", "Programmation Orientée Objet (POO)", "Tests unitaires (JUnit)", "Android Studio", "XML (Extensible Markup Language)", "Retrofit (Bibliothèque Android)", "Spring Boot (Sécurité)", "PostgreSQL", "API (Intégration)", "RESTful API", "Déploiement (Cloud)", "Gestion de projet (Outils)"], "summary": "Étudiant en 3ème année de BUT Informatique, je suis passionné par le développement logiciel et cherche à renforcer mes compétences. Je possède une solide base en Java, Spring Boot, et développement mobile Android, avec une expérience pratique en bases de données et intégration d''API. Motivé et rigoureux, je suis prêt à apporter ma curiosité et mon esprit d''équipe à votre projet.", "education": [{"year": "2026", "degree": "BUT Informatique (3ème année)", "school": "IUT Paris Rives de Seine"}, {"year": "2023", "degree": "BTS Comptabilité et Gestion", "school": "Courbevoie"}, {"year": "2021", "degree": "Bac STMG Mention Bien (Gestion Finance)", "school": "Courbevoie"}], "strengths": ["Solides compétences en développement Java et Spring Boot, avec maîtrise des bases de données SQL.", "Expérience pratique en développement mobile Android et intégration d''API REST.", "Maîtrise des outils de développement et de gestion de version (Git, IntelliJ, Eclipse).", "Rigoureux, autonome et doté d''un esprit d''équipe, avec une forte capacité d''adaptation.", "Capacité à concevoir et développer des solutions complètes, de la modélisation à l''intégration continue."], "experiences": [{"role": "Stagiaire Informatique", "company": "CSF", "isCurrent": true, "startDate": "2025", "description": ["Installation et mise à jour d''une application de planification de projets sur un nouveau serveur", "Utilisation de Java, Web Service, GitLab, PuTTY"]}, {"role": "Stagiaire Assistant Comptable", "company": "Jerard Créatis", "endDate": "2022", "isCurrent": false, "startDate": "2022", "description": ["Passage des écritures pour de multiples entreprises de différents statuts"]}], "personalInfo": {"email": "nicolas.chanjou@gmail.com", "phone": "06 95 66 23 66", "title": "Développeur Junior", "lastName": "CHANJOU", "firstName": "Nicolas"}}', 'https://xiphltvpnsconvlrytjc.supabase.co/storage/v1/object/public/cv-original/1773676612965_CHANJOU_Nicolas_CV.pdf', NULL, 'reviewing', '2026-03-16 15:56:53.474735+00', '2026-03-16 15:56:53.474735+00', NULL, 25000, 0),
