	('f154bce4-5e8b-4a48-82f1-e600a2efb0dd', '{"skills": [], "summary": "Souhaitant monter en compétences et renforcer mes acquis, je recherche un stage qui me permettra de progresser en développement logiciel et d''apporter ma motivation et ma curiosité à votre équipe.", "education": [], "strengths": [], "experiences": [], "personalInfo": {"email": "nicolas.chanjou@gmail.com", "phone": "06 95 66 23 66", "title": "Stagiaire en développement logiciel", "lastName": "CHANJOU", "firstName": "Nicolas"}}', 'https://xiphltvpnsconvlrytjc.supabase.co/storage/v1/object/public/cv-original/1773676846072_CHANJOU_Nicolas_CV.pdf', NULL, 'reviewing', '2026-03-16 16:00:46.596966+00', '2026-03-16 16:00:46.596966+00', NULL, 25000, 0),
	('33d62358-671b-4a3c-b2f1-8ec40ee1d8e2', '{"skills": ["PHP", "JavaScript", "TypeScript", "Python", "HTML", "CSS", "Sass", "Symfony", "Laravel", "React.js", "Vue.js", "Angular", "Node.js", "Express.js", "Flask", "jQuery", "API Platform", "React Native", "Twig", "Redux Saga", "MySQL", "MongoDB", "MariaDB", "NoSQL", "Git", "GitLab", "GitHub", "CI/CD", "UX/UI Design", "Docker", "Microsoft Azure", "Amazon Web Services (AWS)", "Material Design", "Bootstrap", "OpenSSL", "API REST", "Pandas", "GeoPandas", "Scrum", "Kanban", "Cloudinary", "DICOM"], "summary": "Développeur Fullstack expérimenté avec 6 ans d''expertise dans le développement d''applications web robustes. Maîtrise approfondie des écosystèmes JavaScript (React.js, Vue.js, Angular, Node.js) et PHP (Symfony, Laravel). Forte capacité à intervenir sur l''ensemble du cycle de vie des projets, de la conception à la maintenance, en environnement agile et cloud, avec une aisance reconnue dans l''intégration d''APIs et l''optimisation des performances.", "education": [{"year": "2020", "degree": "Développeur web et web mobile (Bac+2)", "school": "Centre Formation Konexio"}, {"year": "2017", "degree": "Diplôme en Informatique et Développement Web/Logiciel et Systèmes", "school": "Institut Camillo Olivetti"}], "strengths": ["Expertise Fullstack avérée sur les environnements PHP (Symfony, Laravel) et JavaScript (React.js, Vue.js, Angular, Node.js), avec 6 ans d''expérience.", "Maîtrise solide de l''intégration et du développement d''APIs REST, incluant API Platform, et de l''interfaçage avec des services tiers.", "Compétences confirmées en pratiques DevOps (Docker, CI/CD, GitLab, AWS/Azure) et en méthodologies agiles (Scrum, Kanban) pour un cycle de développement efficace.", "Capacité à intervenir sur l''ensemble du cycle de vie des projets, de la conception des fonctionnalités à la maintenance corrective et l''optimisation des performances.", "Expérience significative en gestion de données (SQL, NoSQL, données géospatiales) et en résolution de problèmes complexes, notamment l''optimisation d''images et la conversion de fichiers."], "experiences": [{"role": "Développeur Fullstack JavaScript PHP", "company": "CROWN HEIGHTS", "isCurrent": true, "startDate": "03/2023", "description": ["Développement de nouvelles fonctionnalités pour une solution d''affichage dynamique (Crown TV).", "Maintenance corrective et évolutive des applications.", "Développement d’une application de tests avec configuration de données arbitraires pour Crown TV.", "Création et intégration d''un explorateur de dossiers de fichiers multimédias.", "Intégration de l''API immobilière pour la distribution d''annonces via CronJob automatique.", "Bascule des alertes Slack vers Teams et implémentation de systèmes de notifications automatiques.", "Développement d''un algorithme pour le redimensionnement d''images avec Cloudinary."]}, {"role": "Développeur Fullstack JavaScript PHP", "company": "DEEP BLOCK", "endDate": "02/2023", "isCurrent": false, "startDate": "06/2022", "description": ["Optimisation, correction de bogues et développement de fonctionnalités pour le projet VitalSign (Symfony 5) – application de signature virtuelle.", "Développement et intégration d''API pour divers projets.", "Création d''une application de repos pour interagir avec une bibliothèque d’APIs REST (OpenApi).", "Développement d''un service de conversion de fichiers (.doc, .docx, .odt, .png, .jpg, .jpeg) en PDF.", "Développement d’API certifiant l''horodatage pour des documents sensibles (contrats, fiches de paie).", "Création de scripts automatisant le traitement de fichiers, la navigation et le remplissage de formulaires.", "Vérification et optimisation des fichiers KML (gestion polygonale géospatiale).", "Développement d’API pour la réduction de la taille des liens originaux (short links)."]}, {"role": "Développeur Fullstack JavaScript", "company": "AZMED", "endDate": "05/2022", "isCurrent": false, "startDate": "10/2020", "description": ["Résolution de bugs et amélioration de l''interface utilisateur pour un outil d’aide au diagnostic basé sur l''IA (Rayvolve IA).", "Optimisation de la responsivité de l''application.", "Ajout de nouveaux utilitaires et options au produit.", "Déploiement, mise à jour et maintenance des applications.", "Développement de nouveaux utilitaires pour Rayvolve IA.", "Développement et/ou amélioration de projets internes (ToolAnalytics, site web officiel Azmed, DICOM Azmed Viewer)."]}, {"role": "Développeur Fullstack PHP JavaScript", "company": "FREELANCER.COM", "endDate": "2020", "isCurrent": false, "startDate": "2019", "description": ["Développement de landing pages, de tableaux de bord et de blogs.", "Développement de fonctions et de méthodes pour la résolution de problèmes au sein des projets.", "Développement d''une plateforme d''administration de stagiaires pour un centre de formation laser, incluant :", "Un module de suivi des progrès académiques/professionnels.", "Un module de regroupement de documents numériques (PDF, DOC, EXE).", "Un module de gestion des présences et absences.", "Un module de suivi des stages."]}, {"role": "Développeur Fullstack PHP JavaScript", "company": "FR4M3STUDIO", "endDate": "2019", "isCurrent": false, "startDate": "2017", "description": ["Développement d''un outil de gestion des clients (Médiashopping) sur Symfony 3, puis Symfony 4.", "Développement de solutions web pour des clients (artisans, boutiques, centres de beauté) visant à créer une vitrine en ligne.", "Développement de solutions pour la gestion des charges importantes et la recherche de clients.", "Développement de pages publicitaires pour les produits et fourniture de moyens de contact simples pour distributeurs/fabricants.", "Développement, mise à jour et optimisation du code source des ressources web.", "Mise en place de systèmes de gestion de données utilisateur.", "Développement de systèmes de notification automatique (email, SMS).", "Optimisation de la protection des données sensibles."]}], "personalInfo": {"title": "Développeur Fullstack", "lastName": "S.", "firstName": "A."}}', 'https://xiphltvpnsconvlrytjc.supabase.co/storage/v1/object/public/cv-original/1773368981048_AS_-_Developpeur_Fullstack_REACT_PHP_Symfony_062023.docx', NULL, 'reviewing', '2026-03-13 02:29:41.883577+00', '2026-03-13 02:29:41.883577+00', NULL, 25000, 0),
