	('bcb6aa0c-a2eb-4627-8910-97d657c3644a', '{"skills": ["Java", "Jakarta EE", "JavaServer Pages (JSP)", "JDBC", "Java Persistence API (JPA)", "Spring Framework", "Spring MVC", "Spring Boot", "Modèle-Vue-Contrôleur (MVC)", "Design Patterns", "Principes SOLID", "Programmation réseau", "Intégration et déploiement continus (CI/CD)", "VBA", "Microsoft Excel", "C (langage)", "C++", "Python", "VB.NET", "HTML", "CSS", "JavaScript", "PHP", "Bootstrap", "XML", "Retrofit", "Oracle Database", "Microsoft Access", "SQL", "PL/SQL", "SQLite", "MySQL", "PostgreSQL", "Microsoft Word", "Microsoft PowerPoint", "GitHub", "GitLab", "PuTTY", "DevOps", "Figma", "Trello", "Modelio", "Sage (logiciel)", "IntelliJ IDEA", "Eclipse", "Android Studio", "Railway", "API REST", "Algorithme de Dijkstra", "Structures de données", "Programmation Orientée Objet (POO)", "JUnit", "Tests unitaires", "Développement Android", "Sécurité des applications", "Authentification", "Déploiement Cloud", "Gestion de projet"], "summary": "Actuellement étudiant en 3ème année de BUT Informatique à l''IUT Paris Rives de Seine, Nicolas Chanhou est à la recherche d''un stage de fin d''études de 14 semaines ou plus. Il est très motivé par le développement logiciel, souhaitant monter en compétences et renforcer ses acquis. Nicolas aspire à apporter sa curiosité et son dynamisme à une équipe innovante en ESN.", "education": [{"year": "2026", "degree": "BUT Informatique", "school": "IUT Paris Rives de Seine"}, {"year": "2023", "degree": "BTS de Comptabilité et Gestion", "school": "Courbevoie"}, {"year": "2021", "degree": "BAC STMG Mention Bien, Spécialités Gestion Finance", "school": "Courbevoie"}], "strengths": ["Solide base technique en Java et son écosystème (JEE, Spring Boot, Spring MVC), ainsi qu''en C, C++, Python et PHP.", "Compétences variées en bases de données (Oracle, MySQL, PostgreSQL, SQL) et en développement front-end (HTML, CSS, JavaScript, Bootstrap).", "Expérience pratique en développement mobile Android, incluant la conception de backends REST sécurisés et l''intégration d''API externes.", "Maîtrise des concepts clés du développement logiciel (Design Patterns, Principes SOLID, POO, CI/CD, Tests unitaires) et des outils (Git, IntelliJ, Eclipse, Android Studio).", "Proactivité et autonomie démontrées à travers des projets concrets, comme un outil de gestion de stock en VBA et une application de suivi énergétique."], "experiences": [{"role": "Stagiaire Informatique", "company": "CSF", "isCurrent": false, "startDate": "2025", "description": ["Installation et mise à jour d''une application de planification de projets sur un nouveau serveur", "Utilisation de Java, Web Service, GitLab et PuTTY"]}, {"role": "Stagiaire Assistant Comptable", "company": "Jerard Créatis", "isCurrent": false, "startDate": "2022", "description": ["Passage des écritures comptables pour de multiples entreprises de différents statuts"]}], "personalInfo": {"email": "nicolas.chanjou@gmail.com", "phone": "06 95 66 23 66", "title": "Étudiant en BUT Informatique", "lastName": "CHANJOU", "location": "Courbevoie, France", "firstName": "Nicolas"}}', 'https://xiphltvpnsconvlrytjc.supabase.co/storage/v1/object/public/cv-original/1773677686037_CHANJOU_Nicolas_CV.pdf', NULL, 'ready', '2026-03-16 16:14:46.491079+00', '2026-03-16 16:14:46.491079+00', NULL, 25000, 300),
	('cdf80948-d25d-4583-a5c7-22e3d8d908fc', '{"skills": ["Java", "Java EE", "Spring Framework", "Spring MVC", "Spring Boot", "Model-View-Controller (MVC)", "Design Patterns", "SOLID Principles", "Network Programming", "CI/CD", "VBA", "Microsoft Excel", "C", "C++", "Python", "VB.NET", "Oracle Database", "Microsoft Access", "SQL", "PL/SQL", "SQLite", "MySQL", "HTML", "CSS", "JavaScript", "PHP", "Bootstrap", "Microsoft Word", "Microsoft PowerPoint", "GitHub", "GitLab", "PuTTY", "DevOps", "Figma", "Trello", "IntelliJ IDEA", "Eclipse", "Algorithms", "Data Structures", "Object-Oriented Programming (OOP)", "Unit Testing", "JUnit", "Android Studio", "XML", "Retrofit", "PostgreSQL", "Platform-as-a-Service (PaaS)", "API Integration", "RESTful APIs", "Backend Development", "Cloud Deployment"], "summary": "Étudiant en 3ème année de BUT Informatique à l''IUT Paris Rives de Seine, Nicolas CHANJOU recherche un stage pour développer ses compétences en développement logiciel. Fort d''une solide base en Java, Spring et JEE, il possède également des connaissances en développement web et mobile. Très motivé, il souhaite intégrer une équipe dynamique pour appliquer ses acquis et contribuer activement à des projets innovants, tout en consolidant ses connaissances techniques.", "education": [{"year": "2026", "degree": "BUT Informatique", "school": "IUT Paris Rives de Seine"}, {"year": "2023", "degree": "BTS Comptabilité et Gestion", "school": "Courbevoie"}, {"year": "2021", "degree": "Bac STMG Mention Bien, Spécialité Gestion Finance", "school": "Courbevoie"}], "strengths": ["Maîtrise des fondamentaux du développement logiciel, notamment Java, Spring et JEE, avec une bonne compréhension des concepts OOP et des Design Patterns.", "Expérience pratique avec une large gamme d''outils et de technologies : bases de données (SQL, MySQL, PostgreSQL), développement web (HTML, CSS, JS, PHP), et mobile (Android Studio).", "Compétences en gestion de projet et collaboration via des outils comme GitHub, GitLab et Trello, ainsi qu''une sensibilisation aux pratiques DevOps et CI/CD.", "Capacité démontrée à travailler en autonomie sur des projets, de la conception aux tests unitaires, comme l''outil de gestion de stock VBA ou l''application mobile Greenplay.", "Profil rigoureux, adaptable et dynamique, avec un fort esprit d''équipe, soutenu par une formation solide en informatique et en gestion."], "experiences": [{"role": "Stagiaire Informatique", "company": "CSF", "endDate": "2025", "location": "", "isCurrent": false, "startDate": "2025", "description": ["Installation et mise à jour d''une application de planification de projets sur un nouveau serveur", "Utilisation de Java, Web Service, GitLab, PuTTY"], "companyDomain": ""}, {"role": "Assistant Comptable Stagiaire", "company": "Jerard Créatis", "endDate": "2022", "location": "", "isCurrent": false, "startDate": "2022", "description": ["Passage des écritures pour de multiples entreprises de différents statuts"], "companyDomain": ""}], "personalInfo": {"email": "nicolas.chanjou@gmail.com", "phone": "06 95 66 23 66", "title": "Étudiant BUT Informatique", "lastName": "CHANJOU", "location": "Courbevoie, France", "firstName": "Nicolas"}}', 'https://xiphltvpnsconvlrytjc.supabase.co/storage/v1/object/public/cv-original/1773677225812_CHANJOU_Nicolas_CV.pdf', NULL, 'ready', '2026-03-16 16:07:06.419956+00', '2026-03-16 16:07:06.419956+00', NULL, 25000, 580);


