	('3ffc2480-90cb-4c75-8d49-cf44cb10f622', '3f6a2c53-ac45-4e85-97b7-36f4113ee790', '{"skills": ["Java", "TypeScript", "JavaScript", "SQL", "Python", "HTML", "CSS", "Angular", "React.js", "Spring Framework", "Hibernate", "PostgreSQL", "MySQL", "MongoDB", "Redis", "Apache Kafka", "RabbitMQ", "Microsoft Azure", "Apache Maven", "Gradle", "Git", "Docker", "GitLab CI/CD", "Jenkins", "Liquibase", "JUnit", "Mockito", "Spring Boot", "Conception d''API REST", "JWT (JSON Web Tokens)", "Oracle Database", "Tesseract OCR", "spaCy", "UiPath RPA", "Grafana", "Apache JMeter", "Développement full-stack", "Développement d''applications web", "Microservices", "Traitement de données", "Méthodes Agiles", "Scrum", "Domain Driven Design", "CQRS (Command Query Responsibility Segregation)", "Architecture logicielle", "CI/CD", "Tests unitaires", "Tests d''intégration", "Revue de code", "Software Craftsmanship"], "summary": "Développeur Java Full-Stack avec 5 ans d''expérience, certifié OCP Java 17, spécialisé dans le développement d''applications web et de systèmes métiers.", "education": [{"year": "Non spécifié", "degree": "Master MIAGE", "school": "Université d''Orléans"}], "strengths": ["Expertise Java Full-Stack solide avec 5 ans d''expérience, certifié OCP Java 17.", "Maîtrise approfondie des architectures modernes (Microservices, Domain Driven Design, CQRS, Architecture hexagonale) et développement d''API REST sécurisées.", "Compétences étendues en écosystèmes Java/Spring Boot/Angular et bases de données (SQL, NoSQL, Oracle), complétées par des technologies de messagerie (Kafka, RabbitMQ) et cloud (Azure).", "Expérience significative en intégration continue/déploiement continu (GitLab CI, Jenkins) et pratiques de qualité logicielle (tests unitaires, d''intégration, code review).", "Fortes soft skills incluant l''esprit d''analyse, l''autonomie, la communication technique et le travail en équipe, essentielles pour des environnements Agile Scrum."], "experiences": [{"role": "Développeur Java/Angular", "company": "Canal+", "endDate": "janvier 2026", "isCurrent": false, "startDate": "septembre 2023", "description": ["Développement des modules Staff (planning et collaborateurs) et Record (enregistrements live) en Java 21 / Spring Boot 3 et Angular 20, avec architecture hexagonale, Domain Driven Design, CQRS et micro-frontend.", "Conception d''API REST sécurisées (JWT), synchrones pour les opérations standards, asynchrones pour les traitements volumineux.", "Mise en place d''un cache Redis pour stocker les métadonnées et assurer le suivi des traitements longs.", "Migration de BDD Oracle de 20 ans d''historique de planning pour 10 000 collaborateurs (~40M d''entrées), idempotente pour cohabiter avec le legacy.", "Implémentation des règles métier complexes : code du travail, statuts intermittents/permanents/multi-métiers.", "Intégration de SAP pour les flux liés à la paie.", "Configuration de la pipeline CI/CD (GitLab CI, Docker) avec tests unitaires et d''intégration (JUnit, Mockito, Wiremock) et validation du schéma BDD (Liquibase).", "Rôle transverse : support fonctionnel, technique, DevOps et UI, mentorat de développeurs."]}, {"role": "Développeur Java/Angular", "company": "EDF", "endDate": "décembre 2023", "isCurrent": false, "startDate": "septembre 2022", "description": ["Développement en Java 11 / Spring Boot et Angular 15 dans une architecture micro-service.", "Conception et d''APIs REST externe et documenté.", "Réduction de la dette technique : mise à niveau de Spring Boot, refactorisation du code, optimisation des requêtes SQL, temps de réponse réduit de 3 min à 20 sec.", "Développement des workflows de publication de dossier d''exploitation.", "Développement de templating de mail avec variables.", "Développement de batchs (Spring Batch, CRON) pour le rapatrier les données d''autres services EDF.", "Tests unitaires et d''intégration (JUnit, Mockito, Wiremock).", "Déploiements sur différents environnements (Jenkins)."]}, {"role": "Développeur Java", "company": "INSA", "endDate": "décembre 2022", "isCurrent": false, "startDate": "septembre 2021", "description": ["Développement from scratch d''une plateforme en architecture microservices (Java, Spring, Kafka et MongoDB).", "Conception de l''architecture orientée message et réalisation de PoC.", "Développement de dashboard Grafana.", "Test de performance via JMeter.", "Conception d''API REST à destination des autres collaborateurs du projet de recherche.", "Échanges en anglais avec un consortium de 20 chercheurs européens, rédaction des spécifications techniques."]}, {"role": "Développeur Java/Python", "company": "Siemens", "endDate": "décembre 2021", "isCurrent": false, "startDate": "septembre 2020", "description": ["Développement d''un microservice de reconnaissance de document (Tesseract OCR).", "Développement d''une IA (Python, spaCy) pour l''extraction de données dans les documents.", "Développement de robots RPA (UiPath) pour automatiser la saisie SAP, en l''absence d''API disponible.", "Développement d''API REST (Java, Spring Boot) pour orchestrer l''IA et les robots UiPath.", "Échanges en anglais avec le client international pour cadrer les besoins fonctionnels."]}], "personalInfo": {"title": "Développeur Java Fullstack", "lastName": "Sakar", "location": "Paris et IDF", "firstName": "Nurullah"}}', 'google/gemini-2.5-flash', '2026-03-17 17:00:40.073754+00');


